#include <bits/stdc++.h>
using namespace std;

class Scandal {
 public:
    void solve() {
        read_input();
        print_output(kosajaru());
    }

 private:
    int n, m;  // n = number of friends, m = number of rules
    vector<vector<int>> adj;  // adjacency list
    vector<vector<int>> rev_adj;  // reversed adjacency list

    void read_input() {
        ifstream fin("scandal.in");
        fin >> n >> m;
        // use 2 * n sizes for positive and negative cases
        // 1 - n (i): positives ; n + 2 * n (i + n): negatives
        // uses adj list and rev adj list to map relations
        adj.resize(2 * n + 1);
        rev_adj.resize(2 * n + 1);
        int x, y, c;
        for (int i = 0; i < m; i++) {
            fin >> x >> y >> c;
            if (c == 0) {
                // x -> -y and -x -> y
                adj[n + y].push_back(x);
                rev_adj[x].push_back(n + y);
                adj[n + x].push_back(y);
                rev_adj[y].push_back(n + x);
            } else if (c == 1) {
                // -x -> -y and y -> x
                adj[n + x].push_back(n + y);
                rev_adj[n + y].push_back(n + x);
                adj[y].push_back(x);
                rev_adj[x].push_back(y);
            } else if (c == 2) {
                // -y -> -x and x -> y
                adj[n + y].push_back(n + x);
                rev_adj[n + x].push_back(n + y);
                adj[x].push_back(y);
                rev_adj[y].push_back(x);
            } else if (c == 3) {
                // y -> -x and x -> -y
                adj[y].push_back(n + x);
                rev_adj[n + x].push_back(y);
                adj[x].push_back(n + y);
                rev_adj[n + y].push_back(x);
            }
        }
        fin.close();
    }

    // dfs throw graph to get the order of the nodes in the stack
    void dfs(vector<vector<int>> &adj_lst, vector<int> &order,
             vector<bool> &visited, int node) {
        order.push_back(node);
        visited[node] = true;
        for (int neigh : adj_lst[node]) {
            if (!visited[neigh]) {
                dfs(adj_lst, order, visited, neigh);
            }
        }
    }

    /*
     * Kosajaru algorithm to find the strongly connected components in a graph
     * using dfs throw graph and reversed graph. The result is the friends
     * that will be invited to the party.
     */
    vector<int> kosajaru() {
        vector<int> invites;
        // order = stack with dfs throw graph
        // ssc_order = stack with dfs throw reversed graph
        vector<int> order, ssc_order;

        vector<bool> visited(n * 2 + 1, false);
        vector<bool> visited_rev(n * 2 + 1, false);
        vector<bool> visited_order(n * 2 + 1, false);

        // Get ssc order with dfs throw graph
        for (int i = 1; i <= n; i++) {
            for (int node = i + n; node > 0; node -= n) {
                if (!visited[node]) {
                    dfs(adj, order, visited, node);
                }
            }
        }

        // Get ssc order with dfs throw reversed graph, using order stack
        while (!order.empty()) {
            int node = order[order.size() - 1];
            order.pop_back();
            if (!visited_rev[node]) {
                dfs(rev_adj, ssc_order, visited_rev, node);
            }
        }

        // Arrange in order the friends that will be invited to the party
        for (int node : ssc_order) {
            if (!visited_order[node]) {
                if (node <= n) {
                    visited_order[node] = true;
                    visited_order[node + n] = true;
                } else {
                    visited_order[node - n] = true;
                    visited_order[node] = true;
                }
                if (node > n) {
                    // If -node is false, result node is true
                    invites.push_back(node - n);
                }
            }
        }
        return invites;
    }

    void print_output(const vector<int>& result) {
        ofstream fout("scandal.out");
        fout << result.size() << '\n';
        for (int i : result) {
            fout << i << '\n';
        }
        fout.close();
    }
};

int main() {
    auto* scandal = new (nothrow) Scandal();
    if (!scandal) {
        cerr << "something went wrong!!";
        return -1;
    }
    scandal->solve();
    delete scandal;
    return 0;
}

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Iterator;
import java.util.List;
import java.util.Stack;

public class Scandal {
	static class Task {
		public static final String INPUT_FILE = "scandal.in";
		public static final String OUTPUT_FILE = "scandal.out";

		public static final int MAX = 2 * 100000 + 10;
		public static ArrayList<ArrayList<Integer>> adj = new ArrayList<>(MAX);
		public static boolean[] visited = new boolean[MAX];
		public static Stack<Integer> stack = new Stack<>();
		public static int[] low = new int[MAX];
		public static int[] time = new int[MAX];
		public static boolean[] inStack = new boolean[MAX];
		public static int[] scc = new int[MAX];
		public static List<List<Integer>> sccComponents = new ArrayList<>();
		public static int sccCounter = 0;
		public static int n, m;
		public static int globalTime = 0;

		public void solve() {
			readInput();
			List<Integer> result = getResult();
			writeOutput(result);
		}

		private void readInput() {
			try {
				BufferedReader br =
					new BufferedReader(new FileReader(INPUT_FILE));
				String[] input = br.readLine().split(" ");
				n = Integer.parseInt(input[0]);
				m = Integer.parseInt(input[1]);

				for (int i = 0; i < 2 * n + 1; i++) {
					adj.add(new ArrayList<>());
				}

				for (int i = 0; i < m; i++) {
					String[] rule = br.readLine().split(" ");
					int x = Integer.parseInt(rule[0]);
					int y = Integer.parseInt(rule[1]);
					int c = Integer.parseInt(rule[2]);

					if (c == 0) {
						addEdges(x, n, y, 0);
						addEdges(y, n, x, 0);
					} else if (c == 1) {
						addEdges(x, n, y, n);
						addEdges(y, 0, x, 0);
					} else if (c == 2) {
						addEdges(y, n, x, n);
						addEdges(x, 0, y, 0);
					} else if (c == 3) {
						addEdges(x, 0, y, n);
						addEdges(y, 0, x, n);
					}
				}

				Arrays.fill(time, -1);
				Arrays.fill(low, -1);
				Arrays.fill(inStack, false);

				for (int i = 1; i <= 2 * n; i++) {
					if (time[i] == -1) {
						tarjanIterative(i);
					}
				}

				br.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private List<Integer> getResult() {
			boolean[] truthValues = new boolean[n + 1];
			if (assignTruthValues(truthValues)) {
				List<Integer> result = new ArrayList<>();
				for (int i = 1; i <= n; i++) {
					if (truthValues[i]) {
						result.add(i);
					}
				}
				return result;
			} else {
				return new ArrayList<>();
			}
		}

		private void writeOutput(List<Integer> result) {
			try {
				PrintWriter pw = new PrintWriter(new FileWriter(OUTPUT_FILE));
				pw.println(result.size());
				for (int x : result) {
					pw.println(x);
				}
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		static void addEdges(int x, int add1, int y, int add2) {
			int finalX = x + add1;
			int finalY = y + add2;
			adj.get(finalX).add(finalY);
		}

		private static boolean assignTruthValues(boolean[] truthValues) {
			for (int i = 1; i <= n; i++) {
				if (scc[i] == scc[i + n]) {
					return false;
				}
				truthValues[i] = scc[i] < scc[i + n];
			}
			return true;
		}

		private void tarjanIterative(int start) {
			Stack<Integer> nodeStack = new Stack<>();
			Stack<Iterator<Integer>> iterStack = new Stack<>();
			nodeStack.push(start);
			iterStack.push(adj.get(start).iterator());

			time[start] = low[start] = ++globalTime;
			stack.push(start);
			inStack[start] = true;

			while (!nodeStack.isEmpty()) {
				int u = nodeStack.peek();
				Iterator<Integer> iter = iterStack.peek();

				if (iter.hasNext()) {
					int v = iter.next();
					if (time[v] == -1) {
						time[v] = low[v] = ++globalTime;
						stack.push(v);
						inStack[v] = true;
						nodeStack.push(v);
						iterStack.push(adj.get(v).iterator());
					} else if (inStack[v]) {
						low[u] = Math.min(low[u], time[v]);
					}
				} else {
					iterStack.pop();
					nodeStack.pop();
					for (int v : adj.get(u)) {
						if (inStack[v]) {
							low[u] = Math.min(low[u], low[v]);
						}
					}

					if (low[u] == time[u]) {
						List<Integer> component = new ArrayList<>();
						while (true) {
							int v = stack.pop();
							inStack[v] = false;
							scc[v] = sccCounter;
							component.add(v);
							if (v == u) {
								break;
							}
						}
						sccComponents.add(component);
						sccCounter++;
					}
				}
			}
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}
